record.field:
for factura in records:
    if factura.bandera:
        continue

    if factura.journal_id.name != 'FACTURAS OUTLET':
        continue

    # Obtener el cliente principal
    cliente = factura.partner_id
    if cliente.type != 'contact' and cliente.parent_id and cliente.parent_id.type == 'contact':
        cliente = cliente.parent_id

    # Validar si el cliente asistió al evento
    if not cliente.attended_event:
        factura.sudo().write({'bandera': True})
        continue

    fecha_factura = factura.invoice_date
    monto_factura = factura.amount_untaxed or 0.0


    for premio_rel in cliente.award_ids:
        premio = premio_rel.award_id

        # Validar lista de precios
        if premio.condicion == 'pricelist' and cliente.property_product_pricelist.id not in premio.pricelist_ids.ids:
            continue

        if premio.fecha_evento_inicio and premio.fecha_evento_fin:
            if not (premio.fecha_evento_inicio <= fecha_factura <= premio.fecha_evento_fin):
                continue

        if premio.fecha_hora_sorteo and fecha_factura > premio.fecha_hora_sorteo.date():
            continue

        condicion = premio.condicion or ''
        valor = premio.valor or 0.0
        acomulable = premio.acomulable
        subtotal = 0.0
        cantidad_extra = 0

        lineas = factura.invoice_line_ids

        if condicion == 'marca':
            lineas = lineas.filtered(
                lambda l: l.product_id.product_tmpl_id.product_brand_id.id in premio.product_brand_ids.ids
            )
        elif condicion == 'categoria':
            lineas = lineas.filtered(
                lambda l: l.product_id.categ_id.id in premio.categ_ids.ids
            )
        elif condicion == 'etiqueta':
            lineas = lineas.filtered(
                lambda l: any(tag.id in premio.tag_ids.ids for tag in l.product_id.product_tmpl_id.product_tag_ids)
            )
        elif condicion == 'producto':
            lineas = lineas.filtered(
                lambda l: l.product_id.product_tmpl_id.id in premio.product_ids.ids
            )

        if not condicion or condicion == 'pricelist':
            subtotal = monto_factura
        else:
            subtotal = sum(line.price_subtotal for line in lineas)

        if valor > 0:
            if subtotal >= valor:
                veces = int(subtotal // valor) if acomulable else 1
                cantidad_extra = veces
        elif lineas:
            if acomulable:
                cantidad_extra = sum(line.quantity for line in lineas)
            else:
                cantidad_extra = len(lineas)

        if cantidad_extra > 0:
            premio_rel.sudo().write({
                'cantidad': premio_rel.cantidad + cantidad_extra,
                'historial': premio_rel.historial + cantidad_extra
            })

            cliente.message_post(
                body=f"Se procesaron por facturas {cantidad_extra} boletos para el premio {premio.name}. "
                     f"Cantidad actual: {premio_rel.cantidad}, Historial: {premio_rel.historial}",
                subtype_xmlid="mail.mt_note"
            )

    factura.sudo().write({'bandera': True})
